"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[5737],{3985(e){e.exports=JSON.parse('{"tag":{"label":"persona:infrastructure-engineer","permalink":"/gsf-patterns/tags/persona-infrastructure-engineer","allTagsPath":"/gsf-patterns/tags","count":15,"items":[{"id":"architecture/system-topology/choose-region-closest-to-users","title":"Choose the region that is closest to users","description":"From an energy-efficiency perspective, it\'s better to shorten the distance a network packet travels so that less energy is required to transmit it. Similarly, from an embodied-carbon perspective, when a network packet traverses through less computing equipment, we are more efficient with hardware.","permalink":"/gsf-patterns/architecture/system-topology/choose-region-closest-to-users"},{"id":"architecture/technology-selection/evaluate-other-cpu-architectures","title":"Evaluate other CPU architectures","description":"Applications are built with a software architecture that best fits the business need they are serving. Cloud providers make it easy to evaluate other CPU types","permalink":"/gsf-patterns/architecture/technology-selection/evaluate-other-cpu-architectures"},{"id":"operations/capacity-management/match-utilization-requirements-of-vm","title":"Match utilization requirements of virtual machines (VMs)","description":"It\'s better to have one VM running at a higher utilization than two running at low utilization rates, not only in terms of energy proportionality but also in terms of embodied carbon. Two servers running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilized server could be more efficiently used for another task or process.","permalink":"/gsf-patterns/operations/capacity-management/match-utilization-requirements-of-vm"},{"id":"operations/capacity-management/match-utilization-requirements-with-pre-configured-server","title":"Match utilization requirements with pre-configured servers","description":"It\'s better to have one VM running at a higher utilization than two running at low utilization rates, not only in terms of energy proportionality but also in terms of embodied carbon. Two servers running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilized server could be more efficiently used for another task or process.","permalink":"/gsf-patterns/operations/capacity-management/match-utilization-requirements-with-pre-configured-server"},{"id":"development/minimizing-deployed-environments","title":"Minimize the total number of deployed environments","description":"In a given application, there may be a need to utilize multiple environments in the application workflow. Typically, a development environment is used for regular updates, while staging or testing enviroments are used to make sure there are no issues before code reaches a production environment where users may have access. Each added environment has an increasing energy impact, which in turn creates more emissions. As such, it is important to understand the necessity of each enviroment and it\'s environmental impact.","permalink":"/gsf-patterns/development/minimizing-deployed-environments"},{"id":"operations/capacity-management/optimize-avg-cpu-utilization","title":"Optimize average CPU utilization","description":"CPU usage and utilization varies throughout the day, sometimes wildly for different computational requirements. The larger the variance between the average and peak CPU utilization values, the more resources need to be provisioned in stand-by mode to absorb those spikes in traffic.","permalink":"/gsf-patterns/operations/capacity-management/optimize-avg-cpu-utilization"},{"id":"architecture/system-topology/reduce-network-traversal-between-VMs","title":"Reduce network traversal between VMs","description":"Placing VMs in the same region or availability zone minimises the physical distance data must travel between instances, reducing the energy consumed by network traversal.","permalink":"/gsf-patterns/architecture/system-topology/reduce-network-traversal-between-VMs"},{"id":"architecture/system-topology/run-ai-models-edge","title":"Run AI models at the edge","description":"Deploy AI inference on edge devices or local infrastructure to reduce data transfer, network energy use, and reliance on centralised cloud compute.","permalink":"/gsf-patterns/architecture/system-topology/run-ai-models-edge"},{"id":"operations/capacity-management/scale-down-unused-applications","title":"Scale down applications when not in use","description":"Applications consume CPU even when they are not actively in use. For example, background timers, garbage collection, health checks, etc. Even when the application is shut down, the underlying hardware is consuming idle power.","permalink":"/gsf-patterns/operations/capacity-management/scale-down-unused-applications"},{"id":"operations/capacity-management/scale-down-kubernetes-workloads","title":"Scale down kubernetes applications when not in use","description":"In order to reduce carbon emissions and costs, Dev&Test Kubernetes clusters can turn off nodes out of office hours. Thereby, optimization is implemented at the cluster level. For production clusters, where nodes need to stay up and running, optimization needs to be implemented at the application level.","permalink":"/gsf-patterns/operations/capacity-management/scale-down-kubernetes-workloads"},{"id":"architecture/system-topology/efficient-hardware-ai-workloads","title":"Select efficient accelerators and instance types for AI workloads","description":"Match AI workloads to the most energy-efficient hardware accelerator or instance type to improve utilisation and reduce energy consumption per inference or training run.","permalink":"/gsf-patterns/architecture/system-topology/efficient-hardware-ai-workloads"},{"id":"operations/time-shift-kubernetes-cron-jobs","title":"Time-shift Kubernetes cron jobs","description":"The carbon emissions of a software system depends on the power consumed by that software, but also on the Carbon intensity of the electricity it is powered on. For this reason, running energy-efficient software on carbon intensive electricity grid, might be inefficient to reduce its global carbon emissions. Carbon aware time scheduling, is about scheduling workloads to execute, when electricity carbon intensity is low.","permalink":"/gsf-patterns/operations/time-shift-kubernetes-cron-jobs"},{"id":"operations/carbon-aware-ai-scheduling","title":"Use carbon-aware scheduling and region selection for AI workloads","description":"Reduce the carbon impact of AI workloads by running them in cloud regions with lower grid carbon intensity and scheduling deferrable jobs during periods of high renewable energy availability.","permalink":"/gsf-patterns/operations/carbon-aware-ai-scheduling"},{"id":"architecture/technology-selection/use-energy-efficient-hardware","title":"Use cloud native processor VMs","description":"Cloud VMs built on energy-efficient processors, such as ARM-based cloud-native chips, can run scale-out workloads with significantly lower energy consumption and embodied carbon than traditional alternatives.","permalink":"/gsf-patterns/architecture/technology-selection/use-energy-efficient-hardware"},{"id":"architecture/technology-selection/use-serverless","title":"Use serverless cloud services","description":"Serverless cloud services scale dynamically with demand and share infrastructure across many applications, reducing idle resource consumption and lowering embodied carbon emissions.","permalink":"/gsf-patterns/architecture/technology-selection/use-serverless"}],"unlisted":false}}')}}]);